// ============================================================================
// split_lines() tests
// ============================================================================

TEST(split_lines_empty) {
    size_t count = 999;
    char** lines = test_split_lines("", 0, &count);
    TEST_ASSERT_NULL(lines);
    TEST_ASSERT_EQ(count, 0);
}

TEST(split_lines_single_line_no_newline) {
    size_t count = 0;
    char** lines = test_split_lines("hello", 5, &count);
    TEST_ASSERT_NOT_NULL(lines);
    TEST_ASSERT_EQ(count, 1);
    TEST_ASSERT_STREQ(lines[0], "hello");
    test_free_lines(lines, count);
}

TEST(split_lines_single_line_with_newline) {
    size_t count = 0;
    char** lines = test_split_lines("hello\n", 6, &count);
    TEST_ASSERT_NOT_NULL(lines);
    // Includes trailing empty line after newline
    TEST_ASSERT_EQ(count, 2);
    TEST_ASSERT_STREQ(lines[0], "hello");
    TEST_ASSERT_STREQ(lines[1], "");
    test_free_lines(lines, count);
}

TEST(split_lines_multiple) {
    const char* text = "line1\nline2\nline3";
    size_t count = 0;
    char** lines = test_split_lines(text, strlen(text), &count);
    TEST_ASSERT_NOT_NULL(lines);
    TEST_ASSERT_EQ(count, 3);
    TEST_ASSERT_STREQ(lines[0], "line1");
    TEST_ASSERT_STREQ(lines[1], "line2");
    TEST_ASSERT_STREQ(lines[2], "line3");
    test_free_lines(lines, count);
}

TEST(split_lines_crlf_normalization) {
    const char* text = "line1\r\nline2\r\n";
    size_t count = 0;
    char** lines = test_split_lines(text, strlen(text), &count);
    TEST_ASSERT_NOT_NULL(lines);
    // Includes trailing empty line after final newline
    TEST_ASSERT_EQ(count, 3);
    TEST_ASSERT_STREQ(lines[0], "line1");
    TEST_ASSERT_STREQ(lines[1], "line2");
    TEST_ASSERT_STREQ(lines[2], "");
    test_free_lines(lines, count);
}

TEST(split_lines_mixed_endings) {
    const char* text = "unix\nwindows\r\nold_mac\r";
    size_t count = 0;
    char** lines = test_split_lines(text, strlen(text), &count);
    TEST_ASSERT_NOT_NULL(lines);
    TEST_ASSERT_EQ(count, 3);
    TEST_ASSERT_STREQ(lines[0], "unix");
    TEST_ASSERT_STREQ(lines[1], "windows");
    test_free_lines(lines, count);
}

TEST(split_lines_empty_lines) {
    const char* text = "a\n\nb\n";
    size_t count = 0;
    char** lines = test_split_lines(text, strlen(text), &count);
    TEST_ASSERT_NOT_NULL(lines);
    // Includes empty line between a and b, plus trailing empty after final newline
    TEST_ASSERT_EQ(count, 4);
    TEST_ASSERT_STREQ(lines[0], "a");
    TEST_ASSERT_STREQ(lines[1], "");
    TEST_ASSERT_STREQ(lines[2], "b");
    TEST_ASSERT_STREQ(lines[3], "");
    test_free_lines(lines, count);
}

// ============================================================================
// line_hash() tests
// ============================================================================

TEST(line_hash_deterministic) {
    uint32_t h1 = test_line_hash("hello world");
    uint32_t h2 = test_line_hash("hello world");
    TEST_ASSERT_EQ(h1, h2);
}

TEST(line_hash_different_strings) {
    uint32_t h1 = test_line_hash("hello");
    uint32_t h2 = test_line_hash("world");
    TEST_ASSERT_NE(h1, h2);
}

TEST(line_hash_empty_string) {
    uint32_t h = test_line_hash("");
    TEST_ASSERT_EQ(h, 5381);  // DJB2 initial value
}

TEST(line_hash_similar_strings) {
    uint32_t h1 = test_line_hash("abc");
    uint32_t h2 = test_line_hash("abd");
    TEST_ASSERT_NE(h1, h2);
}

TEST(line_hash_whitespace_matters) {
    uint32_t h1 = test_line_hash("a b");
    uint32_t h2 = test_line_hash("ab");
    TEST_ASSERT_NE(h1, h2);
}

// ============================================================================
// myers_char_diff() tests
// ============================================================================

TEST(myers_identical_strings) {
    const wchar_t* s = L"hello";
    bool changed_old[5] = {true, true, true, true, true};
    bool changed_new[5] = {true, true, true, true, true};

    bool ok = test_myers_char_diff(s, 5, s, 5, changed_old, changed_new);
    TEST_ASSERT_TRUE(ok);

    for (int i = 0; i < 5; i++) {
        TEST_ASSERT_FALSE(changed_old[i]);
        TEST_ASSERT_FALSE(changed_new[i]);
    }
}

TEST(myers_single_char_change) {
    const wchar_t* old_s = L"hello";
    const wchar_t* new_s = L"hallo";  // e -> a
    bool changed_old[5] = {};
    bool changed_new[5] = {};

    bool ok = test_myers_char_diff(old_s, 5, new_s, 5, changed_old, changed_new);
    TEST_ASSERT_TRUE(ok);

    TEST_ASSERT_FALSE(changed_old[0]);  // 'h' unchanged
    TEST_ASSERT_TRUE(changed_old[1]);   // 'e' changed
    TEST_ASSERT_FALSE(changed_old[2]);  // 'l' unchanged

    TEST_ASSERT_FALSE(changed_new[0]);  // 'h' unchanged
    TEST_ASSERT_TRUE(changed_new[1]);   // 'a' is new
    TEST_ASSERT_FALSE(changed_new[2]);  // 'l' unchanged
}

TEST(myers_insertion) {
    const wchar_t* old_s = L"ac";
    const wchar_t* new_s = L"abc";
    bool changed_old[2] = {};
    bool changed_new[3] = {};

    bool ok = test_myers_char_diff(old_s, 2, new_s, 3, changed_old, changed_new);
    TEST_ASSERT_TRUE(ok);

    TEST_ASSERT_FALSE(changed_old[0]);  // 'a' unchanged
    TEST_ASSERT_FALSE(changed_old[1]);  // 'c' unchanged
    TEST_ASSERT_FALSE(changed_new[0]);  // 'a' unchanged
    TEST_ASSERT_TRUE(changed_new[1]);   // 'b' is inserted
    TEST_ASSERT_FALSE(changed_new[2]);  // 'c' unchanged
}

TEST(myers_deletion) {
    const wchar_t* old_s = L"abc";
    const wchar_t* new_s = L"ac";
    bool changed_old[3] = {};
    bool changed_new[2] = {};

    bool ok = test_myers_char_diff(old_s, 3, new_s, 2, changed_old, changed_new);
    TEST_ASSERT_TRUE(ok);

    TEST_ASSERT_FALSE(changed_old[0]);  // 'a' unchanged
    TEST_ASSERT_TRUE(changed_old[1]);   // 'b' was deleted
    TEST_ASSERT_FALSE(changed_old[2]);  // 'c' unchanged
}

TEST(myers_empty_old) {
    const wchar_t* new_s = L"abc";
    bool changed_new[3] = {};

    bool ok = test_myers_char_diff(L"", 0, new_s, 3, nullptr, changed_new);
    TEST_ASSERT_TRUE(ok);

    // All new characters should be marked as changed (insertions)
    TEST_ASSERT_TRUE(changed_new[0]);
    TEST_ASSERT_TRUE(changed_new[1]);
    TEST_ASSERT_TRUE(changed_new[2]);
}

TEST(myers_empty_new) {
    const wchar_t* old_s = L"abc";
    bool changed_old[3] = {};

    bool ok = test_myers_char_diff(old_s, 3, L"", 0, changed_old, nullptr);
    TEST_ASSERT_TRUE(ok);

    // All old characters should be marked as changed (deletions)
    TEST_ASSERT_TRUE(changed_old[0]);
    TEST_ASSERT_TRUE(changed_old[1]);
    TEST_ASSERT_TRUE(changed_old[2]);
}

TEST(myers_complete_replacement) {
    const wchar_t* old_s = L"abc";
    const wchar_t* new_s = L"xyz";
    bool changed_old[3] = {};
    bool changed_new[3] = {};

    bool ok = test_myers_char_diff(old_s, 3, new_s, 3, changed_old, changed_new);
    TEST_ASSERT_TRUE(ok);

    // All characters should be marked as changed
    for (int i = 0; i < 3; i++) {
        TEST_ASSERT_TRUE(changed_old[i]);
        TEST_ASSERT_TRUE(changed_new[i]);
    }
}

